def diff_dicts(old: dict, new: dict) -> dict:
    """
    Compare two flat dictionaries and describe the differences.

    Parameters
    ----------
    old : dict
        The original dictionary.
    new : dict
        The updated dictionary.

    Returns
    -------
    dict
        A dictionary with exactly three keys:
        - "added": dict of {key: value} for keys present only in `new`
                   (value taken from `new`).
        - "removed": dict of {key: value} for keys present only in `old`
                     (value taken from `old`).
        - "changed": dict of {key: {"old": old_value, "new": new_value}}
                     for keys present in both dicts but with different values.

        Keys with equal values in both `old` and `new` are omitted from
        all three sections. Keys may be of any hashable type.
    """
    old_keys = set(old.keys())
    new_keys = set(new.keys())

    added_keys = new_keys - old_keys
    removed_keys = old_keys - new_keys
    common_keys = old_keys & new_keys

    added = {k: new[k] for k in added_keys}
    removed = {k: old[k] for k in removed_keys}
    changed = {
        k: {"old": old[k], "new": new[k]}
        for k in common_keys
        if old[k] != new[k]
    }

    return {
        "added": added,
        "removed": removed,
        "changed": changed,
    }


